import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup, ZoomControl } from "react-leaflet";
import L from "leaflet";
import 'leaflet/dist/leaflet.css';
import Alert from "./Alert";

// Marker icons
const greenIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const redIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();

        // Check for newly ghost buses
        data.forEach(bus => {
          const prevBus = buses.find(b => b.id === bus.id);
          if (bus.status === "ghost" && (!prevBus || prevBus.status !== "ghost")) {
            setAlerts(prev => [...prev, `Bus ${bus.id} is now a GHOST!`]);
            // Auto remove after 5 seconds
            setTimeout(() => setAlerts(prev => prev.filter(a => a !== `Bus ${bus.id} is now a GHOST!`)), 5000);
          }
        });

        setBuses(data);
      } catch (error) {
        console.error("Error fetching bus data:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 5000);
    return () => clearInterval(interval);
  }, [buses]);

  return (
    <>
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={11}
        style={{ height: "70vh", width: "100%" }}
        scrollWheelZoom={true}
        zoomControl={false}
      >
        <ZoomControl position="topright" />
        <TileLayer
          url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
          attribution=""
        />

        {buses.map(bus => (
          <Marker
            key={bus.id}
            position={[bus.lat, bus.lon]}
            icon={bus.status === "ghost" ? redIcon : greenIcon}
          >
            <Popup>
              Bus ID: {bus.id} <br />
              Status: {bus.status}
            </Popup>
          </Marker>
        ))}
      </MapContainer>

      {/* Alerts */}
      {alerts.map((msg, index) => (
        <Alert key={index} message={msg} />
      ))}
    </>
  );
};

export default MapComponent;
